mapper.select:
SELECT COUNT(1)
FROM workflow_template
WHERE page_code = #{pageCode}
AND enabled = #{enabled}

  AND (name ILIKE CONCAT('%', #{keyword}, '%') OR template_code ILIKE CONCAT('%', #{keyword}, '%'))

SELECT id, page_code, template_code, name, config_json, enabled, is_default, updated_at
FROM workflow_template
WHERE page_code = #{pageCode}
AND enabled = #{enabled}

  AND (name ILIKE CONCAT('%', #{keyword}, '%') OR template_code ILIKE CONCAT('%', #{keyword}, '%'))

ORDER BY is_default DESC, updated_at DESC, id DESC
LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE workflow_template
SET is_default = #{isDefault}, updated_at = NOW()
WHERE id = #{id}

mapper.select:
SELECT COUNT(1)
FROM workflow_task
WHERE page_code = #{pageCode}
  AND template_code = #{templateCode}
  AND status = 'pending'

mapper.update:
UPDATE data_record
SET status = 'submitted',
    workflow_template_code = #{templateCode},
    updated_at = NOW(),
    updated_by = #{operator}
WHERE id = #{recordId} AND page_code = #{pageCode}

mapper.select:
SELECT id
FROM workflow_task
WHERE record_id = #{recordId}
  AND node_code = #{nodeCode}
  AND status = 'pending'
  AND assignee = #{assignee}
ORDER BY id
LIMIT 1

mapper.update:
UPDATE data_record
SET status = #{status},
    updated_at = NOW(),
    updated_by = #{operator}
WHERE id = #{recordId} AND page_code = #{pageCode}

UPDATE data_record
SET updated_at = NOW(), updated_by = #{operator}
WHERE id = #{recordId} AND page_code = #{pageCode}

mapper.select:
SELECT COUNT(1)
FROM data_record r
WHERE r.created_by = #{operator}
AND r.page_code = #{pageCode}
AND r.status = #{status}
AND r.data::text ILIKE CONCAT('%', #{keywords}, '%')
